// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer;

import java.nio.charset.StandardCharsets;
import java.util.Base64;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;

/**
 * Helpers for building stable {@link PatternKey} instances.
 */
public final class PatternKeys {

	private static final String CONSTANT_OBJECT_PREFIX = "urn:rdf4j:learned:constantObject:";
	private static final Map<String, IRI> CONSTANT_OBJECT_KEYS = new ConcurrentHashMap<>();

	private PatternKeys() {
	}

	public static IRI predicateKey(IRI predicate, Value object) {
		if (object != null) {
			String key = predicate.stringValue() + "\u0000" + object;
			return CONSTANT_OBJECT_KEYS.computeIfAbsent(key,
					value -> SimpleValueFactory.getInstance()
							.createIRI(CONSTANT_OBJECT_PREFIX + Base64.getUrlEncoder()
									.withoutPadding()
									.encodeToString(value.getBytes(StandardCharsets.UTF_8))));
		}
		return predicate;
	}
}
